const correlationId = `recon-${new Date().toISOString().slice(0,10)}-${Math.floor(Math.random()*1e6)}`;
const d = new Date(Date.now() - 86400000);
const yesterday = d.toISOString().slice(0,10);
return [{ json: { correlationId, yesterday } }];

const yesterday = $node['Stamp date'].json.yesterday;
const rows = $items().map(i => i.json);
const candidates = rows.filter(r => r.op === 'issue' && (r.appliedAt || '').startsWith(yesterday) && r.status === 'issued');
return candidates.map(json => ({ json: { ...json, correlationId: $node['Stamp date'].json.correlationId } }));

const r = $json;
const expected = 'ISSUED';
const actual = r.body?.result?.status ?? 'UNKNOWN';
const match = actual === expected;
return [{ json: {
  correlationId: r.correlationId,
  orderId: r.orderId,
  provider: r.provider,
  invoiceNumber: r.body?.result?.invoiceNumber ?? null,
  expected,
  actual,
  match
}}];
